# compute similarity: token F1
def token_f1(a,b):
    toks_a = a.split()
    toks_b = b.split()
    common = set(toks_a) & set(toks_b)
    if not toks_a or not toks_b:
        return 0.0
    prec = len(common)/len(set(toks_b))
    rec = len(common)/len(set(toks_a))
    if prec+rec==0: 
        f1=0.0
    else:
        f1 = 2*prec*rec/(prec+rec)
    return f1

def lcs_len(a,b):
    # dynamic programming for LCS
    n=len(a); m=len(b)
    dp=[0]*(m+1)
    for i in range(1,n+1):
        prev=0
        for j in range(1,m+1):
            tmp=dp[j]
            if a[i-1]==b[j-1]:
                dp[j]=prev+1
            else:
                dp[j]=max(dp[j], dp[j-1])
            prev=tmp
    return dp[m]

def lcs_ratio(a,b):
    L=lcs_len(a,b)
    return L/len(a) if len(a)>0 else 0.

