def lcsstr_len(a,b):
    # longest common substring (contiguous)
    n=len(a); m=len(b)
    dp=[[0]*(m+1) for _ in range(n+1)]
    best=0
    for i in range(1,n+1):
        for j in range(1,m+1):
            if a[i-1]==b[j-1]:
                dp[i][j]=dp[i-1][j-1]+1
                if dp[i][j]>best:
                    best=dp[i][j]
            else:
                dp[i][j]=0
    return best

def lcsstr_ratio(a,b):
    L=lcsstr_len(a,b)
    return L/len(a) if len(a)>0 else 0

def best_matches_lcsstr(target_norm, data, field='ayah_text', topn=10):
    out=[]
    for q in data:
        text=q[field]
        n=normalize_arabic(text)
        ratio=lcsstr_ratio(target_norm, n)
        if ratio>0:
            out.append((ratio, q, n))
    out.sort(key=lambda x: x[0], reverse=True)
    return out[:topn]

